parameters.jsCode:
// Get email from Gmail trigger
const email = $node["📧 Support Email Received"]?.json?.From || "";

// Get ERP data
const customers = $json.customers || [];
const inventory = $json.inventory || [];

// Find matching customer
const matched = customers.find(c =>
  email.toLowerCase().includes(c.email.toLowerCase())
);

// Fallback if not found
const customer = matched || {
  name: "Customer",
  customerId: "Unknown",
  orders: []
};

return [
  {
    json: {
      customer,
      orders: customer.orders,
      inventory
    }
  }
];

